	@Test
	public void volatileBranchFilterIsEvaluatedPerJoinedSolution() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI subject = vf.createIRI(EX, "volatileHub");
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			for (int i = 1; i <= 3; i++) {
				conn.add(subject, p1, vf.createIRI(EX, "volatileA" + i));
				conn.add(subject, p2, vf.createIRI(EX, "volatileB" + i));
			}
		}
		CallIndexFunction function = new CallIndexFunction();
		FunctionRegistry registry = FunctionRegistry.getInstance();
		registry.add(function);
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(*) AS ?c) WHERE {\n"
				+ "  VALUES ?s { ex:volatileHub }\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "  FILTER(<" + CALL_INDEX_FUNCTION + ">('a', ?a) > 1)\n"
				+ "  FILTER(<" + CALL_INDEX_FUNCTION + ">('b', ?b) > 1)\n"
				+ "}";
		String previous = System.getProperty(NATIVE_FLAG);
		try {
			function.reset();
			List<String> nativeRows = rows(query);
			function.reset();
			System.setProperty(NATIVE_FLAG, "false");
			List<String> genericRows = rows(query);
			assertThat(nativeRows).as("volatile filter must run once per complete joined solution")
					.isEqualTo(genericRows);
			System.setProperty(NATIVE_FLAG, "true");
			function.reset();
			assertThat(strategy(query))
					.as("an extension function without an affirmative purity contract must stay at its row boundary")
					.isEqualTo("aggState");
		} finally {
			registry.remove(function);
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
	}

